using System.Runtime.InteropServices;

class EnvVarCheck
{
    // .NET 9 breaking change: GetEnvironmentVariable returns null for
    // empty env vars on Linux. Use native getenv to distinguish
    // "not set" (NULL pointer) from "explicitly empty" (pointer to "").
    [DllImport("libc")]
    private static extern IntPtr getenv(string name);

    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        IntPtr ptr = getenv("MY_FLAG");
        if (ptr == IntPtr.Zero)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

